import { getServiceBySlug } from "@/lib/fetchers";
import Container from "@/components/ui/Container";
import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
import { Button } from "@/components/ui/Button";
import type { Metadata } from "next";

interface Props {
  params: Promise<{ slug: string }>;
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { slug } = await params;
  const service = await getServiceBySlug(slug);
  
  if (!service) return { title: "Service Not Found" };

  return {
    title: service.title,
    description: service.description,
  };
}

const DUMMY_SERVICES = [
  {
    title: "Social Media Management",
    slug: "social-media",
    description: "We handle your social presence from strategy to execution, ensuring your brand stays relevant and engaged.",
    content: "Our comprehensive social media management includes content creation, community management, and detailed analytics reporting.",
    image: "https://picsum.photos/seed/social/1200/800"
  },
  {
    title: "SEO Optimization",
    slug: "seo",
    description: "Dominate search results and drive organic traffic with our data-driven SEO strategies.",
    content: "From technical SEO audits to content optimization and link building, we cover all aspects of search engine visibility.",
    image: "https://picsum.photos/seed/seo/1200/800"
  }
];

export default async function ServiceDetailPage({ params }: Props) {
  const { slug } = await params;
  let service = await getServiceBySlug(slug);

  if (!service) {
    service = DUMMY_SERVICES.find(s => s.slug === slug) as any;
  }

  if (!service) {
    notFound();
  }

  return (
    <div className="py-24 space-y-24">
      <Container>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
          <div className="space-y-8">
            <Link href="/services" className="text-indigo-600 font-bold uppercase tracking-widest text-sm">
              ← All Services
            </Link>
            <h1 className="text-4xl md:text-6xl font-bold tracking-tight leading-tight">
              {service.title}
            </h1>
            <p className="text-xl text-slate-600 leading-relaxed">
              {service.description}
            </p>
            <Button size="lg" asChild>
              <Link href="/contact">Get a Custom Quote</Link>
            </Button>
          </div>
          <div className="relative aspect-video lg:aspect-square rounded-[3rem] overflow-hidden shadow-2xl">
            <Image
              src={service.image || `https://picsum.photos/seed/${service.slug}/800/800`}
              alt={service.title}
              fill
              className="object-cover"
              priority
            />
          </div>
        </div>
      </Container>

      <section className="bg-slate-50 py-24">
        <Container>
          <div className="max-w-3xl mx-auto space-y-12">
            <div className="space-y-6">
              <h2 className="text-3xl md:text-4xl font-bold">What's Included</h2>
              <p className="text-lg text-slate-600 leading-relaxed">
                {service.content || "Our approach is holistic and results-oriented. We don't just provide a service; we become an extension of your team."}
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {[
                "Strategic Planning",
                "Weekly Reporting",
                "Dedicated Account Manager",
                "Custom Content Creation",
                "Competitor Analysis",
                "Performance Optimization"
              ].map((item) => (
                <div key={item} className="flex items-center gap-4 p-4 bg-white rounded-2xl shadow-sm border border-slate-100">
                  <div className="w-6 h-6 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center flex-shrink-0">
                    <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
                  </div>
                  <span className="font-semibold text-slate-700">{item}</span>
                </div>
              ))}
            </div>
          </div>
        </Container>
      </section>

      <Container>
        <div className="p-12 md:p-24 rounded-[3rem] bg-slate-900 text-white text-center space-y-8">
          <h2 className="text-3xl md:text-5xl font-bold">Ready to see results?</h2>
          <p className="text-xl text-slate-400 max-w-2xl mx-auto">
            Schedule a free 30-minute strategy session with one of our experts.
          </p>
          <Button size="lg" variant="outline" className="bg-white text-slate-900 hover:bg-slate-100 border-none" asChild>
            <Link href="/contact">Book Your Session</Link>
          </Button>
        </div>
      </Container>
    </div>
  );
}
